#include <bits/stdc++.h>
using namespace std;
#define ll long long
const int N=200005;
ll n,m,c,k,a[N],s[N];
bool check(int x,int y)
{
	ll s1=s[x],s2=s[y]-s[x],s3=s[n]-s[y];
	if(min(s2,s3)<s1) return 0;
	if(max(s2,s3)-min(s2,s3)>m) return 0;
	if(min(s2,s3)-s1>m) return 0;
	return 1;
}
ll fun(int x,int y)
{
	ll s1=s[x],s2=s[y]-s[x],s3=s[n]-s[y];
	if(s2>s3) swap(s2,s3);
	ll sum=0;
	if(k<c)
	{
		return s3*k;
	}
	sum+=s3*c;
	sum+=max(min(k-c,c),(ll)0)*s2+max(min(k-2*c,c),(ll)0)*s1;
	return sum;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>m>>c>>k;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		s[i]=s[i-1]+a[i];
	}
	if(3*c<k)
	{
		cout<<"-1\n";
		return 0;
	}
	ll ans=-1;
	for(int i=0;i<=n;i++)
	{
		int tmp=lower_bound(s+1,s+1+n,2*s[i])-s;
		if(s[tmp]-s[i]<=s[n]-s[tmp])
		{
			if(s[n]-s[tmp]-(s[tmp]-s[i])<=m)
			{
				if(check(i,tmp)) ans=max(ans,fun(i,tmp));
			}
			else
			{
				int tmp2=lower_bound(s+1,s+1+n,(s[n]+s[i]-m)/2)-s;
				if(check(i,tmp2)) ans=max(ans,fun(i,tmp2));
			}
		}
		int tmp2=upper_bound(s+1,s+1+n,min((s[n]+s[i]+m)/2,s[n]-s[i]))-s-1;
		if(check(i,tmp2)) ans=max(ans,fun(i,tmp2));
	}
	cout<<ans;
	return 0;
}
